import{_ as a,o as e,c as i,a2 as n}from"./chunks/framework.y1bVONfd.js";const m=JSON.parse('{"title":"Adding Animations","description":"","frontmatter":{},"headers":[],"relativePath":"guides/adding-animations.md","filePath":"guides/adding-animations.md"}'),s={name:"guides/adding-animations.md"};function o(l,t,d,r,h,g){return e(),i("div",null,[...t[0]||(t[0]=[n(`<h1 id="adding-animations" tabindex="-1">Adding Animations <a class="header-anchor" href="#adding-animations" aria-label="Permalink to &quot;Adding Animations&quot;">​</a></h1><p>How to add scroll-triggered animations to your WebBeagle pages.</p><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><ol><li>Select a section on the canvas</li><li>Click <strong>🎬 Animate</strong> in the toolbar</li><li>Toggle <strong>ON</strong></li><li>Choose a preset (fade-up is default)</li><li>Click <strong>✨ Stagger All Children</strong></li></ol><p>Done. The section and its children now animate on scroll.</p><h2 id="choosing-an-animation-preset" tabindex="-1">Choosing an Animation Preset <a class="header-anchor" href="#choosing-an-animation-preset" aria-label="Permalink to &quot;Choosing an Animation Preset&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Preset</th><th>Effect</th><th>Best For</th></tr></thead><tbody><tr><td><strong>fade-up</strong></td><td>Fades in while sliding up 40px</td><td>Sections, cards, general content</td></tr><tr><td><strong>fade-in</strong></td><td>Pure opacity fade, no movement</td><td>Subtle reveals, text elements</td></tr><tr><td><strong>slide-left</strong></td><td>Slides in from the left</td><td>Sidebars, lists, decorative elements</td></tr><tr><td><strong>slide-right</strong></td><td>Slides in from the right</td><td>Image reveals, alternating layouts</td></tr><tr><td><strong>zoom-in</strong></td><td>Scales up from 92% while fading</td><td>Hero elements, featured cards</td></tr></tbody></table><h2 id="adjusting-timing" tabindex="-1">Adjusting Timing <a class="header-anchor" href="#adjusting-timing" aria-label="Permalink to &quot;Adjusting Timing&quot;">​</a></h2><h3 id="stagger-delay" tabindex="-1">Stagger Delay <a class="header-anchor" href="#stagger-delay" aria-label="Permalink to &quot;Stagger Delay&quot;">​</a></h3><p>Time between each child&#39;s animation start. Lower = faster cascade.</p><ul><li><strong>0ms</strong> — all children animate simultaneously</li><li><strong>120ms</strong> — subtle cascade (default)</li><li><strong>300ms+</strong> — dramatic entrance</li></ul><h3 id="duration" tabindex="-1">Duration <a class="header-anchor" href="#duration" aria-label="Permalink to &quot;Duration&quot;">​</a></h3><p>How long each individual animation takes.</p><ul><li><strong>600ms</strong> — snappy</li><li><strong>800ms</strong> — natural (default)</li><li><strong>1500ms+</strong> — dramatic slow reveal</li></ul><h2 id="animate-everything-example" tabindex="-1">Animate Everything Example <a class="header-anchor" href="#animate-everything-example" aria-label="Permalink to &quot;Animate Everything Example&quot;">​</a></h2><p>A fully animated homepage:</p><table tabindex="0"><thead><tr><th>Section</th><th>Preset</th><th>Stagger</th><th>Why</th></tr></thead><tbody><tr><td>Hero badge</td><td>fade-in</td><td>— (single)</td><td>Subtle entrance</td></tr><tr><td>Hero stats</td><td>fade-up</td><td>100ms</td><td>Quick cascade</td></tr><tr><td>Services cards</td><td>fade-up</td><td>120ms</td><td>Staggered reveal</td></tr><tr><td>Steps</td><td>slide-left</td><td>150ms</td><td>Sequential process</td></tr><tr><td>Testimonials</td><td>fade-up</td><td>150ms</td><td>Social proof cascade</td></tr><tr><td>CTA button</td><td>zoom-in</td><td>— (single)</td><td>Spotlight effect</td></tr></tbody></table><h2 id="animating-a-single-element" tabindex="-1">Animating a Single Element <a class="header-anchor" href="#animating-a-single-element" aria-label="Permalink to &quot;Animating a Single Element&quot;">​</a></h2><p>Select any element (heading, button, image) and:</p><ol><li>Open 🎬 Animate</li><li>Toggle ON</li><li>Choose preset</li><li>Click ✨ Stagger All Children</li></ol><p>The engine detects no children and makes the element its own animation target.</p><h2 id="load-triggered-animation" tabindex="-1">Load-Triggered Animation <a class="header-anchor" href="#load-triggered-animation" aria-label="Permalink to &quot;Load-Triggered Animation&quot;">​</a></h2><p>Set <strong>Trigger</strong> to <strong>On Page Load</strong> for elements that should animate immediately when the page loads:</p><ol><li>Select the hero section</li><li>Open 🎬 Animate</li><li>Set Trigger: On Page Load</li><li>All children animate immediately (no scroll needed)</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Use &quot;On Page Load&quot; for above-the-fold content. Use &quot;On Scroll&quot; for everything below.</p></div><h2 id="css-customization" tabindex="-1">CSS Customization <a class="header-anchor" href="#css-customization" aria-label="Permalink to &quot;CSS Customization&quot;">​</a></h2><p>Advanced users can adjust animation properties via data attributes:</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">section</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> data-animate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;slide-left&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">         data-stagger</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;200&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">         data-duration</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1000&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">         data-easing</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cubic-bezier(0.34,1.56,0.64,1)&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">         data-initial-opacity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.2&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">         data-offset</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;60&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h3 id="easing-functions" tabindex="-1">Easing Functions <a class="header-anchor" href="#easing-functions" aria-label="Permalink to &quot;Easing Functions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Value</th><th>Feel</th></tr></thead><tbody><tr><td><code>cubic-bezier(0.16, 1, 0.3, 1)</code></td><td>Smooth deceleration (default)</td></tr><tr><td><code>cubic-bezier(0.34, 1.56, 0.64, 1)</code></td><td>Bouncy overshoot</td></tr><tr><td><code>ease-out</code></td><td>Gentle deceleration</td></tr><tr><td><code>ease-in-out</code></td><td>Symmetric</td></tr><tr><td><code>linear</code></td><td>Constant speed</td></tr></tbody></table><h2 id="verifying-animations" tabindex="-1">Verifying Animations <a class="header-anchor" href="#verifying-animations" aria-label="Permalink to &quot;Verifying Animations&quot;">​</a></h2><ol><li>Save and publish</li><li>Visit the preview URL</li><li>Open DevTools → Elements tab</li><li>Look for <code>.wb-animated</code> classes on your elements</li><li>Scroll the page — watch <code>animation-play-state</code> change from <code>paused</code> to <code>running</code></li></ol><h2 id="common-issues" tabindex="-1">Common Issues <a class="header-anchor" href="#common-issues" aria-label="Permalink to &quot;Common Issues&quot;">​</a></h2><h3 id="animations-don-t-trigger" tabindex="-1">Animations don&#39;t trigger? <a class="header-anchor" href="#animations-don-t-trigger" aria-label="Permalink to &quot;Animations don&#39;t trigger?&quot;">​</a></h3><ul><li>[ ] Element has <code>data-animate</code> attribute (saved, not just in canvas)</li><li>[ ] Element or its children have <code>data-animate-item</code></li><li>[ ] You&#39;re scrolling enough to trigger IntersectionObserver (threshold 0.1 = 10% visible)</li></ul><h3 id="stagger-not-working" tabindex="-1">Stagger not working? <a class="header-anchor" href="#stagger-not-working" aria-label="Permalink to &quot;Stagger not working?&quot;">​</a></h3><ul><li>[ ] Children are tagged with <code>data-animate-item</code> (use ✨ Stagger All Children)</li><li>[ ] Stagger value is &gt; 0ms</li><li>[ ] Check for <code>.visible</code> hardcoded in HTML (removes animation entirely)</li></ul><h3 id="animation-plays-but-resets" tabindex="-1">Animation plays but resets? <a class="header-anchor" href="#animation-plays-but-resets" aria-label="Permalink to &quot;Animation plays but resets?&quot;">​</a></h3><p>Check <code>animation-fill-mode: both</code> — without it, elements snap back after animation completes. The <code>.wb-animated</code> class includes this.</p>`,39)])])}const u=a(s,[["render",o]]);export{m as __pageData,u as default};
